import torch.nn.functional as F
import math
import os

class RepresentationMode:
    QLT = "QLT"  # Quantized Lookup Table (per-layer codebook)
    LRF = "LRF"  # Low-Rank Factorization
    FP = "FP"    # Full Precision

class DynamicConv1D(nn.Module):
    def __init__(self, nf, nx, config, initial_mode):
        super().__init__()
        self.nf = nf
        self.nx = nx
        self.config = config
        self.grad_norm_ema = 0.0
        self.ema_decay = 0.99 # For smoothing gradient norm
        self._param_hook_handle = None

        # Internal storage for parameter tensors in different modes
        self._ql_codebook_tensor, self._ql_indices_tensor = None, None
        self._lr_U_tensor, self._lr_V_tensor = None, None
        self._fp_W_tensor = None
        self._bias_tensor = torch.zeros(nf, dtype=config.dtype, device='cpu')

        self._initialize_baseline_fp_weights()
        self._set_active_mode(initial_mode, initial_activation=True)

    def _initialize_baseline_fp_weights(self):
        stdv = 1. / math.sqrt(self.nx)
        self._fp_W_tensor = (torch.rand(self.nx, self.nf, dtype=self.config.dtype, device='cpu') * 2 * stdv).add_(-stdv)

    def _get_current_effective_W(self):
        if hasattr(self, 'codebook_param'):
            return self.codebook_param[self.indices_buffer].clone().detach()
        elif hasattr(self, 'U_param'):
            return (self.U_param @ self.V_param).clone().detach()
        elif hasattr(self, 'weight_param'):
            return self.weight_param.clone().detach()
        else:
            # Fallback for initial state before any params are registered
            return self._fp_W_tensor.clone().detach().to(self.config.device) # Assume device needs for SVD later

    def _unregister_current_params(self):
        for param_name in ['weight_param', 'codebook_param', 'U_param', 'V_param', 'bias_param']:
            if hasattr(self, param_name):
                delattr(self, param_name)
        if hasattr(self, 'indices_buffer'):
            delattr(self, 'indices_buffer')
        if self._param_hook_handle:
            self._param_hook_handle.remove()
            self._param_hook_handle = None

    def _register_new_params(self, params_dict):
        for name, tensor in params_dict.items():
            self.register_parameter(name, nn.Parameter(tensor.to(self.config.device)))

        # Attach gradient hook to the *primary* trainable parameter of the active mode
        active_param = None
        if self.current_mode == RepresentationMode.QLT:
            active_param = self.codebook_param
        elif self.current_mode == RepresentationMode.LRF:
            active_param = self.U_param # Can be U_param, or combined norm of U_param/V_param
        elif self.current_mode == RepresentationMode.FP:
            active_param = self.weight_param

        if active_param is not None:
            def grad_norm_hook(grad):
                if grad is not None:
                    current_grad_norm = grad.norm().item()
                    if self.grad_norm_ema == 0:
                        self.grad_norm_ema = current_grad_norm
                    else:
                        self.grad_norm_ema = self.ema_decay * self.grad_norm_ema + (1 - self.ema_decay) * current_grad_norm
            self._param_hook_handle = active_param.register_hook(grad_norm_hook)

    def _set_active_mode(self, new_mode: str, initial_activation: bool = False):
        if self.current_mode == new_mode and not initial_activation:
            return

        self._unregister_current_params()
        self.current_mode = new_mode

        # Retrieve previous full weight for conversion, or use baseline if first time
        prev_W = self._get_current_effective_W() # This should be on device for SVD etc.

        if new_mode == RepresentationMode.QLT:
            if self._ql_codebook_tensor is None or initial_activation:
                # Perform simple clustering-like init for QLT from prev_W
                unique_vals = prev_W.reshape(-1).unique(sorted=False)
                codebook_size = min(len(unique_vals), self.config.ARS_QLT_CODEBOOK_SIZE)
                if len(unique_vals) > codebook_size:
                    perm = torch.randperm(len(unique_vals), device=prev_W.device)
                    codebook_init = unique_vals[perm[:codebook_size]].to(self.config.dtype)
                else:
                    codebook_init = F.pad(unique_vals, (0, codebook_size - len(unique_vals)), 'constant', 0).to(self.config.dtype)

                distances = (prev_W.unsqueeze(-1) - codebook_init).abs()
                indices_init = distances.argmin(dim=-1)

                self._ql_codebook_tensor = codebook_init.cpu()
                self._ql_indices_tensor = indices_init.to(torch.uint8).cpu() # Assume <= 256 for uint8
            self._register_new_params({'codebook_param': self._ql_codebook_tensor, 'bias_param': self._bias_tensor})
            self.register_buffer('indices_buffer', self._ql_indices_tensor.to(self.config.device))

        elif new_mode == RepresentationMode.LRF:
            if self._lr_U_tensor is None or self._lr_V_tensor is None or initial_activation:
                # Perform SVD to get low-rank factorization from prev_W
                U_init, S_init, Vh_init = torch.linalg.svd(prev_W.float(), full_matrices=False)
                rank = min(self.config.ARS_LRF_RANK, S_init.numel())
                self._lr_U_tensor = (U_init[:, :rank] @ torch.diag_embed(S_init[:rank]**0.5)).to(self.config.dtype).cpu()
                self._lr_V_tensor = (Vh_init[:rank, :] * (S_init[:rank]**0.5).unsqueeze(0)).to(self.config.dtype).cpu()
            self._register_new_params({'U_param': self._lr_U_tensor, 'V_param': self._lr_V_tensor, 'bias_param': self._bias_tensor})

        elif new_mode == RepresentationMode.FP:
            if self._fp_W_tensor is None or initial_activation:
                # Simply store the full weight matrix for FP
                self._fp_W_tensor = prev_W.cpu()
            self._register_new_params({'weight_param': self._fp_W_tensor, 'bias_param': self._bias_tensor})

        # After switching, ensure the current mode reflects the tensor stored, not params
        if initial_activation: self.current_mode = new_mode # Only set if it was initial

    def _get_active_weight(self):
        if self.current_mode == RepresentationMode.QLT:
            return self.codebook_param[self.indices_buffer].to(self.config.dtype)
        elif self.current_mode == RepresentationMode.LRF:
            return self.U_param @ self.V_param
        else: # FP
            return self.weight_param

    def forward(self, x):
        original_shape = x.size()
        x_flat = x.view(-1, self.nx)
        weight = self._get_active_weight()
        output_flat = F.linear(x_flat, weight.T, self.bias_param)
        return output_flat.view(original_shape[:-1] + (self.nf,))

    def get_compressed_size(self): # Estimate saved size for artifact
        if self.current_mode == RepresentationMode.QLT:
            # Codebook (FP16) + Indices (UINT8, assuming <=256 codebook size)
            return (self.config.ARS_QLT_CODEBOOK_SIZE * 2) + (self.nx * self.nf * 1)
        elif self.current_mode == RepresentationMode.LRF:
            # U (nx, r) + V (r, nf) in FP16
            return (self.nx * self.config.ARS_LRF_RANK * 2) + (self.config.ARS_LRF_RANK * self.nf * 2)
        else: # FP
            # Full weight (nx, nf) in FP16
            return (self.nx * self.nf * 2)

class Conv1D(nn.Module):

class MLP(nn.Module):
    def __init__(self, config):
        super().__init__()
        self.c_fc    = DynamicConv1D(4 * config.n_embd, config.n_embd, config, config.ARS_INITIAL_REP_MODE)
        self.gelu    = nn.GELU()
        self.c_proj  = DynamicConv1D(config.n_embd, 4 * config.n_embd, config, config.ARS_INITIAL_REP_MODE)
